IF NOT EXISTS (SELECT * FROM sys.tables WHERE name = 'WorkOrders') BEGIN CREATE TABLE [WorkOrders] ([Id] INT IDENTITY(1,1) NOT NULL, [WorkOrderNumber] NVARCHAR(30) NOT NULL DEFAULT '', [MaintenanceRequestId] INT NOT NULL, [Status] NVARCHAR(50) NOT NULL DEFAULT 'Open', [AssignedTo] NVARCHAR(200) NULL, [Notes] NVARCHAR(MAX) NULL, [CreatedBy] NVARCHAR(200) NOT NULL DEFAULT '', [CreatedAt] DATETIME2 NOT NULL, [CompletedAt] DATETIME2 NULL, [TenantId] UNIQUEIDENTIFIER NOT NULL, [IsOnboarded] BIT NOT NULL DEFAULT 0, [OnboardedAtUtc] DATETIMEOFFSET NULL, [OnboardedByUserId] NVARCHAR(MAX) NULL, CONSTRAINT [PK_WorkOrders] PRIMARY KEY ([Id]), CONSTRAINT [FK_WorkOrders_MaintenanceRequests_MaintenanceRequestId] FOREIGN KEY ([MaintenanceRequestId]) REFERENCES [MaintenanceRequests]([Id]) ON DELETE CASCADE); CREATE UNIQUE INDEX [IX_WorkOrders_MaintenanceRequestId] ON [WorkOrders] ([MaintenanceRequestId]); CREATE UNIQUE INDEX [IX_WorkOrders_TenantId_WorkOrderNumber] ON [WorkOrders] ([TenantId], [WorkOrderNumber]); PRINT 'Created.'; END ELSE PRINT 'Already exists.'; IF NOT EXISTS (SELECT * FROM [__EFMigrationsHistory] WHERE [MigrationId] = '20260313131717_AddWorkOrders') INSERT INTO [__EFMigrationsHistory] ([MigrationId],[ProductVersion]) VALUES ('20260313131717_AddWorkOrders','8.0.0');
